"""
MKT Christ-in-Every-Verse Commentary — Genesis chapters 17–19
Run: python3 scripts/zc-christ-genesis-17-19.py

Source data used:
- data/interlinear/genesis.json
- data/translation/draft/mediating/genesis.json (MKT text)
- data/commentary/mkt-christ/genesis.json (existing: chs 1–12 complete)

Key Christological decisions:
- Ch17 circumcision: primary NT connections are Col 2:11 (circumcision done by
  Christ), Rom 4:11 (seal of faith-righteousness), Luke 2:21 (Jesus himself
  circumcised on the eighth day), and Phil 3:3 (the true circumcision). The covenant
  sign points beyond itself to the heart-transformation Christ performs.
- Ch17 covenant: "everlasting covenant" (v7) fulfilled in the new covenant through
  Christ's blood per Heb 13:20. The covenant that narrows from Abraham → Isaac
  (vv19-21) is the pattern Paul uses in Gal 3:16 (seed = Christ) and Rom 9:7-8.
- Ch18 theophany: the "LORD appeared" to Abraham in human form. Some church fathers
  read this as a Christophany (pre-incarnate appearance); at minimum it is a genuine
  divine appearance that anticipates the incarnation. The divine visitor's question
  (18:14) is echoed verbatim in Luke 1:37.
- Abraham's intercession (18:22-33): treated as a type of Christ's intercession
  (Heb 7:25; Rom 8:34), with the key distinction that Abraham intercedes from
  outside the situation while Christ intercedes from within it, bearing the judgment.
- Sodom's destruction (19:24-25): explicit NT type of final judgment (2 Pet 2:6;
  Luke 17:29; Jude 7).
- Lot's wife (19:26): Jesus himself cites this in Luke 17:32 as a warning about
  the cost of looking back when fleeing judgment.
- Moab from Lot's daughters (19:36-37): Ruth the Moabite is in Christ's genealogy
  (Matt 1:5). God redeems even the most broken origins for his redemptive purpose.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

# INTENT: mkt-christ commentary for Genesis 17–19 covering the Abrahamic covenant
#   sign (circumcision), the renewal of the impossible promise (18:14/Luke 1:37),
#   Abraham's intercession as type of Christ's, and Sodom's judgment as type of
#   the final judgment Christ executes and from which he saves.
# CHANGE? If data/commentary/mkt-christ/genesis.json structure changes, update
#   load_comm/save_comm helpers in Z_COMMENTARY_SCRIPT_GUIDE.md.
# VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-christ/genesis.json')); print(len(d.get('17',{})), len(d.get('18',{})), len(d.get('19',{})))" should print "27 33 38".

NEW_DATA = {
"17": {
"1": "<p>&#8220;I am God Almighty (<em>ʾēl šadday</em>); walk before me faithfully and be blameless.&#8221; The divine name <em>El Shaddai</em> &#8212; used with the patriarchs before the Sinai revelation of YHWH (Exod 6:3) &#8212; names God as the all-sufficient one who can do what is humanly impossible. Rev 1:8 applies &#8220;the Almighty&#8221; (<em>pantokrat&#333;r</em>) to Christ: &#8220;I am the Alpha and the Omega, says the Lord God, who is, and who was, and who is to come, the Almighty.&#8221; The God who defines himself as El Shaddai to Abraham is the same God who is fully revealed in Christ as the Almighty. &#8220;Walk before me faithfully and be blameless&#8221; &#8212; Christ alone perfectly fulfills this requirement; his blamelessness (<em>tāmîm</em>) is credited to those who are in him (1 Cor 1:30).</p>",
"2": "<p>&#8220;I will make my covenant between me and you.&#8221; The covenant God initiates with Abram is the founding legal framework of the Messianic promise. Paul calls 12:3 (the parallel promise) &#8220;the gospel announced in advance to Abraham&#8221; (Gal 3:8). The covenant line that begins here runs through Isaac, Jacob, Judah, David, and ultimately to Christ, &#8220;who has become for us wisdom from God &#8212; that is, our righteousness, holiness and redemption&#8221; (1 Cor 1:30). The multiplication of numbers promised here is fulfilled not biologically but spiritually: &#8220;if you belong to Christ, then you are Abraham&#8217;s seed, and heirs according to the promise&#8221; (Gal 3:29).</p>",
"3": "<p>Abraham falls facedown before God. The posture of prostrate worship before the divine presence runs through Scripture to its NT form: John falls &#8220;as if dead&#8221; at the feet of the risen Christ (Rev 1:17); the four living creatures and twenty-four elders &#8220;fall down before the Lamb&#8221; (Rev 5:8). The appropriate response to God&#8217;s presence is the same posture whether before the God of Abraham or before the Lamb who is Christ. The prostration of Abraham prefigures the universal worship of Christ that God the Father desires (Phil 2:10&#8211;11 &#8212; &#8220;at the name of Jesus every knee will bow&#8221;).</p>",
"4": "<p>&#8220;You will be the father of many nations.&#8221; Paul in Gal 3:7&#8211;8 makes the Christological connection: &#8220;those who have faith are children of Abraham&#8221; and &#8220;all nations will be blessed through you.&#8221; The fatherhood of many nations that God promises Abraham is fulfilled through Christ, who gathers &#8220;every tribe and language and people and nation&#8221; (Rev 5:9) into the one family of Abraham. Abraham becomes the father of many nations not through biology but through Christ, in whom &#8220;there is neither Jew nor Gentile&#8221; &#8212; all are one in him and all are Abraham&#8217;s seed (Gal 3:28&#8211;29).</p>",
"5": "<p>The name change: Abram (&#8220;exalted father&#8221;) to Abraham (&#8220;father of a multitude of nations&#8221;). The name change marks a new identity defined by divine promise rather than present circumstance. Christ gives new names to those who overcome (Rev 2:17 &#8212; &#8220;a white stone with a new name written on it&#8221;; Rev 3:12 &#8212; &#8220;I will write on them the name of my God&#8221;). The identity-transforming name-change that God gives Abraham is the pattern of the identity transformation Christ works in his people: &#8220;if anyone is in Christ, the new creation has come&#8221; (2 Cor 5:17).</p>",
"6": "<p>&#8220;Kings will come from you.&#8221; The royal promise embedded in the Abrahamic covenant runs to David and beyond David to Christ, the King of kings. The fulfillment is explicit in the genealogy: &#8220;A record of the genealogy of Jesus the Messiah the son of David, the son of Abraham&#8221; (Matt 1:1). The kings that come from Abraham include Saul, David, Solomon, and the entire Davidic line &#8212; all of which are types of the ultimate King who comes from Abraham&#8217;s seed. Rev 19:16 &#8212; &#8220;King of kings and Lord of lords&#8221; &#8212; is the fulfillment of &#8220;kings will come from you.&#8221;</p>",
"7": "<p>&#8220;I will establish my covenant as an everlasting covenant.&#8221; Heb 13:20 makes the fulfillment explicit: &#8220;the God of peace, who through the blood of the eternal covenant brought back from the dead our Lord Jesus, that great Shepherd of the sheep.&#8221; The everlasting covenant of v7 is the covenant that Christ mediates through his death and resurrection &#8212; the new covenant that is &#8220;eternal&#8221; because Christ&#8217;s blood, unlike animal blood, does not need to be repeated (Heb 9:12; 10:14). &#8220;To be your God and the God of your descendants&#8221; is fulfilled in Christ&#8217;s promise: &#8220;I am with you always, to the very end of the age&#8221; (Matt 28:20).</p>",
"8": "<p>&#8220;The whole land of Canaan...I will give as an everlasting possession.&#8221; Paul in Gal 3:16 identifies &#8220;your offspring/seed&#8221; as Christ: &#8220;the promises were spoken to Abraham and to his seed...meaning one person, who is Christ.&#8221; The land promise is the type of the inheritance Christ secures &#8212; &#8220;an inheritance that can never perish, spoil or fade &#8212; kept in heaven for you&#8221; (1 Pet 1:4). Heb 11:10 says Abraham was looking for &#8220;the city with foundations, whose architect and builder is God&#8221; &#8212; not merely the land of Canaan but the new creation. Christ is both the heir of the promise and the one who makes all who are in him co-heirs (Rom 8:17).</p>",
"9": "<p>&#8220;You must keep my covenant, you and your descendants after you.&#8221; The covenant obligation falls on Abraham and his household. The problem of covenant-keeping &#8212; which Israel will continually fail &#8212; is resolved in Christ: &#8220;by one sacrifice he has made perfect forever those who are being made holy&#8221; (Heb 10:14). Christ is the one who keeps the covenant on behalf of those who cannot: &#8220;he became the source of eternal salvation for all who obey him&#8221; (Heb 5:9). The covenant obligation that Abraham accepts here is the obligation that Christ fulfills for his people through his perfect obedience.</p>",
"10": "<p>&#8220;Every male among you shall be circumcised.&#8221; Circumcision as the covenant sign points beyond the physical act to the spiritual reality that Christ accomplishes. Col 2:11 &#8212; &#8220;In him you were also circumcised with a circumcision not performed by human hands. Your whole self ruled by the flesh was put off when you were circumcised by Christ.&#8221; Paul in Rom 2:29 &#8212; &#8220;circumcision is circumcision of the heart, by the Spirit&#8221; &#8212; applies the Deut 30:6 promise to the work of Christ&#8217;s Spirit. The physical sign commands what the Spirit performs in those who are united to Christ.</p>",
"11": "<p>&#8220;It will be the sign of the covenant between me and you.&#8221; Paul in Rom 4:11 explains the significance: Abraham &#8220;received circumcision as a sign, a seal of the righteousness that he had by faith while he was still uncircumcised.&#8221; Circumcision is a sign of the prior reality of faith-righteousness &#8212; it points to the righteousness credited by faith, not earned by law. This is precisely the righteousness of Christ that is credited to all who believe (Rom 4:23&#8211;24; Phil 3:9). The sign that circumcision is points to what Christ gives freely.</p>",
"12": "<p>Every male circumcised on the eighth day. Luke 2:21 &#8212; &#8220;on the eighth day, when it was time to circumcise the child, he was named Jesus.&#8221; The Son of God submits to the covenant sign that pointed to his own work of spiritual circumcision. Christ undergoes the physical circumcision of the old covenant in order to accomplish the spiritual circumcision of the new. His submission to the law he fulfilled &#8212; &#8220;born under the law, to redeem those under the law&#8221; (Gal 4:4&#8211;5) &#8212; begins in this eighth-day obedience to his own covenant&#8217;s demands.</p>",
"13": "<p>&#8220;My covenant in your flesh is to be an everlasting covenant.&#8221; The covenant written in flesh anticipates the new covenant written on hearts &#8212; &#8220;not on tablets of stone but on tablets of human hearts&#8221; (2 Cor 3:3); &#8220;I will put my law in their minds and write it on their hearts&#8221; (Jer 31:33). Christ mediates the covenant that supersedes the outward sign with the inward reality: &#8220;he is the mediator of a new covenant, that those who are called may receive the promised eternal inheritance&#8221; (Heb 9:15). The covenant written in flesh is the type; the covenant written by the Spirit through Christ is the antitype.</p>",
"14": "<p>The uncircumcised male &#8220;will be cut off from his people; he has broken my covenant.&#8221; The penalty for covenant-breaking is exclusion from the community of the promise. Christ bears the ultimate &#8220;cutting off&#8221; that covenant-breakers deserve: he was &#8220;cut off from the land of the living&#8221; (Isa 53:8) &#8212; the penalty of covenant-breaking falling on the one who kept it perfectly. The exclusion that covenant-breakers face is the exclusion that Christ absorbed, so that those who are in him are included in the covenant community rather than cut off (Eph 2:12&#8211;13).</p>",
"15": "<p>Sarah&#8217;s name change &#8212; from Sarai to Sarah (both mean &#8220;princess,&#8221; but the change is covenantally significant). Like Abraham&#8217;s renaming, Sarah&#8217;s marks the transformation of identity through divine purpose rather than present reality. The new name that God gives to Sarah is the new name Christ gives to his people: Rev 2:17 &#8212; &#8220;a white stone with a new name written on it, known only to the one who receives it.&#8221; The identity that covenant grace confers is the identity that the old name could not contain.</p>",
"16": "<p>&#8220;I will bless her so that she will be the mother of nations; kings of peoples will come from her.&#8221; Sarah as mother of nations through Isaac anticipates the new Jerusalem as the mother of believers: Gal 4:26&#8211;27 &#8212; &#8220;the Jerusalem that is above is free, and she is our mother. For it is written: &#8216;Be glad, barren woman, you who never bore a child...&#8217;&#8221; (Isa 54:1). The barren Sarah who becomes mother of many nations is the type of the new covenant community that produces children &#8220;not from the free woman&#8217;s descendant but from the slave woman&#8217;s&#8221; &#8212; that is, children of promise and grace (Gal 4:23).</p>",
"17": "<p>Abraham laughed &#8212; &#8220;Will a son be born to a man a hundred years old?&#8221; Paul holds Abraham&#8217;s eventual faith as the model of faith in the resurrection: &#8220;Against all hope, Abraham in hope believed and so became the father of many nations&#8230; Without weakening in his faith, he faced the fact that his body was as good as dead &#8212; since he was about a hundred years old &#8212; and that Sarah&#8217;s womb was also dead. Yet he did not waver through unbelief regarding the promise of God&#8221; (Rom 4:18&#8211;20). The initial laughter does not negate the faith that came; and the God who makes a dead womb fruitful is the God who raises the dead &#8212; &#8220;the God who gives life to the dead and calls into being things that were not&#8221; (Rom 4:17).</p>",
"18": "<p>Abraham&#8217;s plea &#8212; &#8220;If only Ishmael might live under your blessing!&#8221; The natural son vs. the son of promise is the theological contrast Paul develops in Gal 4:21&#8211;31: Hagar/Ishmael represent the covenant of law and human effort (Sinai); Sarah/Isaac represent the covenant of grace and divine promise (the Jerusalem above). Paul concludes: &#8220;Now you, brothers and sisters, like Isaac, are children of promise&#8221; (Gal 4:28). Christ is the ultimate child of promise &#8212; born not of the will of the flesh but of the Spirit (John 1:13; Luke 1:35). Ishmael is not abandoned but is not the covenant heir.</p>",
"19": "<p>&#8220;Your wife Sarah will bear you a son, and you will call him Isaac. I will establish my covenant with him as an everlasting covenant.&#8221; The covenant is through Isaac specifically &#8212; not Ishmael. Paul in Rom 9:7&#8211;8 uses this to argue that election is by grace: &#8220;not all who are descended from Israel are Israel. Nor because they are his descendants are they all Abraham&#8217;s children. On the contrary, &#8216;It is through Isaac that your offspring will be reckoned.&#8217; In other words, it is not the children by physical descent who are God&#8217;s children, but it is the children of the promise who are regarded as Abraham&#8217;s offspring.&#8221; The covenant narrows from Abraham to Isaac to Jacob to Judah to David to Christ &#8212; the single seed who is the covenant head (Gal 3:16).</p>",
"20": "<p>Ishmael will be blessed but is not in the covenant line. God&#8217;s blessing extends beyond the covenant line through common grace; twelve rulers will come from Ishmael (vv20; 25:12&#8211;16), fulfilled precisely in Israel&#8217;s history. But the specific Messianic promise &#8212; the seed through whom all nations are blessed &#8212; runs through Isaac. The distinction Paul draws in Gal 3:16 between the general blessing and the specific covenant promise maps onto v20: general blessing (Ishmael) vs. covenant heir (Isaac = Christ). God&#8217;s generosity is universal; his covenant purpose is particular and comes to its point in Christ.</p>",
"21": "<p>&#8220;But my covenant I will establish with Isaac.&#8221; The covenant through Isaac, not Ishmael, is the model of divine election that Paul uses in Rom 9:10&#8211;13 (extended to Esau and Jacob) to argue that election is &#8220;not by works but by him who calls&#8221; (Rom 9:11). The narrowing of the promise &#8212; from all humanity to Shem, to Abraham, to Isaac, to Jacob, to Judah, to David, to Christ &#8212; is the progressive focusing of election that terminates in one person, Jesus Christ, who then becomes the basis of inclusion for all who believe (Gal 3:28&#8211;29). The &#8220;but...with Isaac&#8221; of v21 foreshadows the &#8220;but...in Christ&#8221; of Pauline theology.</p>",
"22": "<p>God finished speaking and &#8220;went up from&#8221; Abraham. The divine departure after the covenant-making theophany. Each appearance of God in the OT is a limited and mediated encounter; the incarnation makes it permanent. Heb 1:1&#8211;2 &#8212; &#8220;in the past God spoke to our ancestors through the prophets at many times and in various ways, but in these last days he has spoken to us by his Son.&#8221; The &#8220;going up&#8221; of God after each theophany points toward the final and permanent departure of God that the ascension of Christ reverses &#8212; he ascended to pour out the Spirit who makes his presence perpetual (Acts 2:33).</p>",
"23": "<p>&#8220;On that very day Abraham took his son Ishmael&#8230; and circumcised them.&#8221; The immediate obedience of the same day &#8212; no delay, no negotiation. Heb 11:8 praises Abraham&#8217;s faith-obedience; 11:17 praises his willingness to offer Isaac. The pattern of immediate, costly obedience that Abraham models is fulfilled perfectly in Christ: &#8220;he humbled himself by becoming obedient to death &#8212; even death on a cross&#8221; (Phil 2:8). Abraham obeys the sign of the covenant on the same day it is given; Christ fulfills the covenant on the day appointed by the Father.</p>",
"24": "<p>Abraham was ninety-nine years old when he was circumcised. The age at which Abraham receives and obeys the sign of the covenant underscores that the covenant is not grounded in human capacity but in divine faithfulness. At ninety-nine &#8212; the age of near-death &#8212; Abraham enters the covenant through a sign that points to new life in the Spirit. Paul&#8217;s point in Rom 4 is precisely that Abraham was justified by faith when his body was &#8220;as good as dead&#8221; &#8212; making the gospel of resurrection-from-the-dead the logical extension of everything that happens to Abraham at ninety-nine.</p>",
"25": "<p>Ishmael was thirteen when circumcised. Ishmael receives the covenant sign even though he is not the covenant heir &#8212; demonstrating that the outward sign and the inward covenant reality can be separated. This is exactly the distinction Paul makes in Rom 2:28&#8211;29: &#8220;A person is not a Jew who is one only outwardly, nor is circumcision merely outward and physical. No, a person is a Jew who is one inwardly; and circumcision is circumcision of the heart, by the Spirit.&#8221; Ishmael&#8217;s circumcision is the cautionary example: the sign does not guarantee the covenant reality that only Christ, through the Spirit, provides.</p>",
"26": "<p>Abraham and Ishmael circumcised on the same day &#8212; the covenant sign applied simultaneously to the covenant heir&#8217;s father and to the non-heir son. The physical sign is applied universally within the household regardless of covenant status; the spiritual reality is received by faith. This is the structure Paul describes in 1 Cor 10:1&#8211;5: Israel was baptized into Moses, ate spiritual food, drank spiritual drink &#8212; but God was not pleased with most of them, because the outward participation did not correspond to inward faith. The sign is universal; the reality is received through faith in Christ.</p>",
"27": "<p>Every male in Abraham&#8217;s household circumcised &#8212; those born in the house and those bought with money. The covenant sign extends beyond the biological family to include purchased servants &#8212; a shadow of the scope of the new covenant community. The church is gathered not by birth but by purchase: &#8220;you were bought with a price&#8221; (1 Cor 6:20; 7:23). Christ purchases his people &#8220;from every tribe and language and people and nation&#8221; (Rev 5:9) &#8212; a wider household even than Abraham&#8217;s. The purchased servant included in the covenant sign anticipates the purchased people included in the new covenant through Christ&#8217;s blood.</p>"
},
"18": {
"1": "<p>&#8220;The LORD appeared to Abraham near the great trees of Mamre.&#8221; The divine appearance in human form &#8212; a theophany in which God takes on visible, physical presence before Abraham. Many early church fathers (Justin Martyr, Irenaeus, Augustine) identified the divine visitor as the pre-incarnate Son of God, given the NT&#8217;s identification of Christ as the one who mediates all divine appearances. John 8:56 &#8212; &#8220;your father Abraham rejoiced at the thought of seeing my day; he saw it and was glad&#8221; &#8212; suggests a real visionary/revelatory encounter with Christ. At minimum, this theophany is the kind of &#8220;face to face&#8221; encounter with God (cf. Exod 33:11) that only the incarnation will make permanent and universally accessible.</p>",
"2": "<p>Abraham sees three men and hurries to meet them, bowing low. Heb 13:2 &#8212; &#8220;do not forget to show hospitality to strangers, for by so doing some people have shown hospitality to angels without knowing it&#8221; &#8212; is written with this scene in mind. The three visitors who appear to Abraham have been read through the centuries as a Trinitarian icon (most famously in Rublev&#8217;s icon of the Trinity). Theologically, the point is that God is not merely distant but comes near &#8212; a truth fulfilled absolutely in the incarnation: &#8220;the Word became flesh and made his dwelling among us&#8221; (John 1:14).</p>",
"3": "<p>&#8220;If I have found favor in your eyes, my lord, do not pass your servant by.&#8221; Abraham&#8217;s plea for the visitors not to pass him by is the hospitable urgency of one who recognizes an extraordinary presence. Christ extends the same invitation to those who would be passed by: &#8220;Zacchaeus, come down immediately. I must stay at your house today&#8221; (Luke 19:5); &#8220;I stand at the door and knock. If anyone hears my voice and opens the door, I will come in and eat with that person&#8221; (Rev 3:20). The hospitality dynamic of Genesis 18 &#8212; Abraham urging the divine visitor to stay &#8212; is mirrored in Christ urging entry into human life.</p>",
"4": "<p>Water to wash feet; rest under the tree. The hospitality of washing feet &#8212; a servant&#8217;s task &#8212; becomes in the NT the paradigm of servant-love that Christ models: &#8220;he got up from the meal, took off his outer clothing, and wrapped a towel around his waist&#8230; and began to wash his disciples&#8217; feet&#8221; (John 13:4&#8211;5). The foot-washing offered by Abraham&#8217;s household to the divine visitors is the act that Christ performs for his disciples &#8212; inverting the expected hierarchy. The hospitality Abraham offers to God, Christ performs for his people.</p>",
"5": "<p>&#8220;Let me get you something to eat, so you can be refreshed.&#8221; Abraham provides nourishment for the divine visitors &#8212; the host feeding his guests. In the Gospel reversals, Christ becomes the host who nourishes: the feeding of five thousand (John 6:1&#8211;15), the Last Supper (Matt 26:26&#8211;28), the resurrection breakfast by the Sea of Galilee (John 21:9&#8211;13). The one who is welcomed as a guest becomes the host; the one who is served becomes the servant who serves. Abraham&#8217;s hospitality is the shadow of the great hospitality of the messianic banquet where Christ is both host and meal (Rev 19:9; John 6:35).</p>",
"6": "<p>Sarah hurries to bake bread from the finest flour. The finest flour (<em>sōlet</em>) is the same quality flour used in the grain offerings of the tabernacle (Lev 2:1) &#8212; the best for the LORD. The consecrated grain offering points toward Christ as the true bread that comes down from heaven (John 6:33&#8211;35); the finest flour offered to the divine visitor is the type of the bread that Christ himself is and gives. The eucharistic resonance &#8212; bread offered to God&#8217;s presence, distributed to guests &#8212; has been noted across the tradition.</p>",
"7": "<p>Abraham runs to select a &#8220;choice, tender calf&#8221; &#8212; the best of the herd, killed and prepared quickly. The sacrifice of the best for the divine guest is the pattern that runs through all of Levitical sacrifice and culminates in Christ: &#8220;for it is impossible for the blood of bulls and goats to take away sins&#8221; (Heb 10:4), but Christ offers himself as &#8220;a sacrifice of atonement&#8221; (Rom 3:25) &#8212; the best, unblemished, given freely. The tender calf killed for the divine guest anticipates the Lamb of God who gives himself (John 1:29).</p>",
"8": "<p>Abraham stands before his guests while they eat. The host serving the honored guest &#8212; standing, not reclining with them &#8212; is the image of attentive service. Christ applies this posture to himself: &#8220;I am among you as one who serves&#8221; (Luke 22:27); the one who is Lord and teacher washes feet (John 13:13&#8211;14). The standing-to-serve posture of Abraham before the divine visitors is the posture Christ assumes toward his disciples at the Last Supper and the resurrection breakfast &#8212; always serving, always present to the needs of those he loves.</p>",
"9": "<p>&#8220;Where is your wife Sarah?&#8221; The divine visitor knows Sarah&#8217;s name and asks about her specific situation. Divine omniscience extending to the particular &#8212; knowing each person by name, knowing their situation. Christ who &#8220;knew all people&#8221; and &#8220;did not need any testimony about mankind, for he knew what was in each person&#8221; (John 2:24&#8211;25); who calls his sheep &#8220;by name&#8221; (John 10:3); who tells the Samaritan woman &#8220;everything you ever did&#8221; (John 4:29). The question &#8220;Where is Sarah?&#8221; is the personal knowledge of the divine that is fully embodied in Christ&#8217;s knowledge of each believer.</p>",
"10": "<p>&#8220;I will surely return to you about this time next year, and Sarah your wife will have a son.&#8221; The divine promise delivered at &#8220;the appointed time&#8221; (<em>mōʿēd</em>). The language of appointed time connects to the sacred calendar of Israel (Lev 23 &#8212; the <em>mōʿăḏîm</em>), all of which Paul calls &#8220;a shadow of the things that were to come; the reality, however, is found in Christ&#8221; (Col 2:17). Christ himself comes at the appointed time: &#8220;when the fullness of time had come, God sent his Son, born of a woman, born under the law&#8221; (Gal 4:4). The divine appointment of the time of Isaac&#8217;s birth is the type of the divine appointment of the time of Christ&#8217;s birth.</p>",
"11": "<p>Abraham and Sarah past the age of bearing children &#8212; the humanly impossible situation. The pattern of impossible births runs through Scripture: Sarah, Rebekah, Rachel, Hannah, Elizabeth &#8212; each barren womb that God opens is a step in the pattern that culminates in Mary&#8217;s virginal conception. Luke 1:36&#8211;37 draws the connection explicitly: Gabriel tells Mary that even Elizabeth has conceived in her old age &#8220;for nothing is impossible with God&#8221; &#8212; the exact logic of Gen 18:14. The humanly impossible condition is the context in which divine power is most clearly displayed &#8212; and the resurrection of Christ is the ultimate display of that power (Eph 1:19&#8211;20).</p>",
"12": "<p>Sarah laughed to herself &#8212; &#8220;after I am worn out...will I now have this pleasure?&#8221; The laugh of unbelief before the divine promise. Yet Heb 11:11 commends Sarah: &#8220;by faith even Sarah, who was past childbearing age, was enabled to bear children because she considered him faithful who had made the promise.&#8221; The movement from laughing disbelief to faith is the movement of every person who encounters the impossible claims of the gospel. Paul in Gal 4:28 calls believers &#8220;children of promise, like Isaac&#8221; &#8212; born not of human laughing doubt but of divine faithfulness that overcomes it.</p>",
"13": "<p>The LORD speaks directly to Abraham about Sarah&#8217;s laughter &#8212; revealing that the divine visitor knows what happens inside the tent. The all-knowing God who hears inward thoughts is the God who, in Christ, &#8220;searches hearts and minds&#8221; (Rev 2:23) and before whom &#8220;nothing in all creation is hidden&#8221; (Heb 4:13). The tender irony of God asking Abraham why Sarah laughed &#8212; not to expose Sarah but to draw her to trust &#8212; is the same gentle confrontation that Christ uses: &#8220;why do you doubt?&#8221; (Matt 14:31); &#8220;do you believe?&#8221; (John 11:26). The question is therapeutic, not accusatory.</p>",
"14": "<p>&#8220;Is anything too hard for the LORD?&#8221; This rhetorical question is echoed verbatim in Gabriel&#8217;s announcement to Mary: &#8220;For nothing will be impossible with God&#8221; (Luke 1:37 &#8212; LXX <em>adunate&#333;</em> rendering the Heb. <em>yippālēʾ</em>). The question asked at Isaac&#8217;s impossible conception is the declaration made at Jesus&#8217; impossible conception. The God who opens a ninety-year-old womb is the God who causes a virgin to conceive. The two impossible births &#8212; Isaac and Jesus &#8212; are connected by this specific verse, which Luke&#8217;s angel consciously echoes. The impossibility that is overcome in both cases is the impossibility that the resurrection makes permanent: &#8220;with God all things are possible&#8221; (Matt 19:26).</p>",
"15": "<p>Sarah denied laughing out of fear; God says &#8220;Yes, you did laugh.&#8221; The gentle insistence of divine truth in the face of human fear and denial. Christ is &#8220;the truth&#8221; (John 14:6) who does not accommodate falsehood but insists on truth &#8212; yet always in order to restore, not condemn. The same gentle truth-insistence appears when Peter denies knowing Jesus and Christ later restores him with the threefold &#8220;do you love me?&#8221; (John 21:15&#8211;17). God&#8217;s refusal to let Sarah&#8217;s denial stand is the refusal of the God of truth to leave his people in self-deception &#8212; because truth is the path to the trust that receives the promise.</p>",
"16": "<p>The men look toward Sodom; Abraham walks with them. The movement from the tent of promise toward the city of judgment mirrors the movement of redemptive history: Christ comes from the Father (the place of divine presence) toward the world under judgment (John 3:17 &#8212; &#8220;God did not send his Son into the world to condemn the world, but to save the world through him&#8221;). Abraham accompanies the divine visitors toward the place of judgment &#8212; as Christ goes with sinners toward the cross, absorbing the judgment they deserve.</p>",
"17": "<p>&#8220;Shall I hide from Abraham what I am about to do?&#8221; The divine deliberation about disclosure &#8212; the language of friendship and prophetic revelation. Amos 3:7 &#8212; &#8220;Surely the Sovereign LORD does nothing without revealing his plan to his servants the prophets.&#8221; Jesus takes this pattern to its fullest expression in John 15:15 &#8212; &#8220;I no longer call you servants, because a servant does not know his master&#8217;s business. Instead, I have called you friends, for everything that I learned from my Father I have made known to you.&#8221; The God who discloses his plans to Abraham is the same God who, in Christ, discloses everything to his friends.</p>",
"18": "<p>&#8220;All nations on earth will be blessed through him&#8221; &#8212; the covenant promise repeated (cf. 12:3). Gal 3:8 &#8212; &#8220;Scripture foresaw that God would justify the Gentiles by faith, and announced the gospel in advance to Abraham.&#8221; The repetition of the promise at the moment of the Sodom interlude underscores that the Abrahamic covenant and its Christological fulfillment is the frame within which the judgment of Sodom must be understood. God&#8217;s purpose to bless all nations through Abraham/Christ is the theological context that gives the Sodom narrative its meaning: judgment and salvation are both expressions of the God who will bless all nations through one seed.</p>",
"19": "<p>&#8220;For I have chosen him, so that he will direct his children and his household after him to keep the way of the LORD by doing what is right and just.&#8221; The covenant community formed by Abraham&#8217;s teaching is the type of the new covenant community formed by Christ&#8217;s teaching. &#8220;Go and make disciples of all nations, teaching them to observe all that I have commanded you&#8221; (Matt 28:19&#8211;20). Christ is both the teacher and the embodiment of the way of the LORD &#8212; &#8220;I am the way and the truth and the life&#8221; (John 14:6). The household Abraham teaches to walk in righteousness and justice is the prototype of the church that Christ teaches to walk in his way.</p>",
"20": "<p>&#8220;The outcry against Sodom and Gomorrah is so great.&#8221; The &#8220;outcry&#8221; (<em>zaʿăqāh</em>) is the cry of the oppressed rising to God &#8212; the same word used for Israel&#8217;s cry in Egypt (Exod 2:23). The God who hears the cry of the oppressed is the God who acts in judgment against the oppressors. Christ as the divine judge (Acts 17:31; John 5:22) hears the cry of the oppressed: &#8220;the wages you failed to pay&#8230; are crying out against you. The cries of the harvesters have reached the ears of the Lord Almighty&#8221; (Jas 5:4). The God who investigates Sodom&#8217;s outcry is the God who will judge all oppression through Christ at the last day.</p>",
"21": "<p>&#8220;I will go down and see.&#8221; The divine descent to investigate &#8212; the same ironic language as Babel (11:5). The descent to see Sodom&#8217;s sin contrasts with the descent to save in the incarnation: &#8220;God did not send his Son into the world to condemn the world, but to save the world through him&#8221; (John 3:17). The Lord comes down to Sodom to judge; the Lord comes down in Christ to save. Yet both descents are expressions of the same divine character: righteous judgment and saving mercy are not opposites but the two faces of the God who takes seriously both sin and love.</p>",
"22": "<p>The men turned toward Sodom; Abraham stood before the LORD and began his intercession. The posture &#8212; standing before the LORD &#8212; is the intercessory posture. Christ is pictured in this posture at God&#8217;s right hand: &#8220;Stephen looked up to heaven and saw the glory of God, and Jesus standing at the right hand of God&#8221; (Acts 7:55 &#8212; standing, not sitting as in Heb 1:3, because he is active on behalf of his people). Abraham&#8217;s standing intercession is the type of Christ&#8217;s perpetual intercession: &#8220;he is able to save completely those who come to God through him, because he always lives to intercede for them&#8221; (Heb 7:25).</p>",
"23": "<p>&#8220;Will you sweep away the righteous with the wicked?&#8221; Abraham&#8217;s intercessory question is rooted in God&#8217;s justice: the righteous should not perish with the wicked. Christ answers this question definitively: the righteous do not perish with the wicked because Christ takes the wicked&#8217;s judgment upon himself so that those who are in him are counted righteous. &#8220;God made him who had no sin to be sin for us, so that in him we might become the righteousness of God&#8221; (2 Cor 5:21). The question Abraham asks &#8212; will the righteous suffer with the guilty? &#8212; is answered at the cross: Christ, the righteous one, suffers for the guilty so that the guilty need not suffer with the condemned.</p>",
"24": "<p>&#8220;What if there are fifty righteous people in the city?&#8221; Abraham&#8217;s intercession works by the logic of substitutionary representation: would the presence of fifty righteous spare the whole? The NT reveals that there is one perfectly righteous one whose presence in the world spares all who shelter in him. Christ is the one righteous one before God (1 John 2:1 &#8212; &#8220;Jesus Christ, the Righteous One&#8221;); his righteousness covers those who are in him. The logic of Abraham&#8217;s intercession &#8212; the righteous few sparing the many &#8212; is the logic of Christ&#8217;s atoning work at its most basic.</p>",
"25": "<p>&#8220;Will not the Judge of all the earth do right?&#8221; Abraham&#8217;s appeal to divine justice is the foundation of biblical theodicy. Paul in Rom 3:25&#8211;26 argues that the cross demonstrates that the Judge of all the earth does do right: &#8220;he did it to demonstrate his righteousness&#8230; so as to be just and the one who justifies those who have faith in Jesus.&#8221; At the cross, God is both just (the penalty is paid) and the justifier (the guilty are acquitted). Abraham&#8217;s question &#8212; will the Judge do right? &#8212; is answered by the cross, where divine justice and divine mercy converge in the person of Christ.</p>",
"26": "<p>&#8220;If I find fifty righteous people in Sodom, I will spare the whole place for their sake.&#8221; The divine willingness to spare the many for the sake of the righteous few is the logic of salvation by substitution. In Christ, this logic reaches its ultimate expression: the many are spared not because of fifty righteous among them but because of one &#8212; the perfectly righteous One. Paul&#8217;s argument in Rom 5:15&#8211;19 is built on precisely this: &#8220;the many died by the trespass of the one man&#8230; how much more did God&#8217;s grace and the gift that came by the grace of the one man, Jesus Christ, overflow to the many!&#8221; The one righteous one spares the many.</p>",
"27": "<p>&#8220;Now that I have been so bold as to speak to the Lord, though I am nothing but dust and ashes.&#8221; Abraham&#8217;s recognition of his own creatureliness before the Creator &#8212; &#8220;dust and ashes&#8221; (echoing 3:19 &#8212; &#8220;for dust you are&#8221;). This creaturely humility before God is the posture Christ enables in the boldness of prayer: &#8220;let us then approach God&#8217;s throne of grace with confidence&#8221; (Heb 4:16). The boldness to approach &#8212; Abraham&#8217;s tentative, qualified boldness &#8212; is given without qualification to those who come through Christ the great High Priest. The dust-and-ashes creature approaches the divine throne not through its own merits but through Christ.</p>",
"28": "<p>The intercession continues &#8212; forty-five righteous. The decreasing numbers mirror the logic of grace: how few is enough? How narrowly can salvation operate? The answer in the NT is: one &#8212; Christ alone is the righteous one who bears the weight of the many. &#8220;For there is one God and one mediator between God and mankind, the man Christ Jesus, who gave himself as a ransom for all people&#8221; (1 Tim 2:5&#8211;6). Abraham counts down toward one; the NT reveals that one is enough &#8212; provided he is the God-man who can bear what no ordinary righteous person could.</p>",
"29": "<p>Forty righteous would spare the city. The intercession presses the logic of substitution further. The pattern of the righteous few bearing the weight for the unrighteous many is carried through to its NT fulfillment: &#8220;the righteous for the unrighteous, to bring you to God&#8221; (1 Pet 3:18). Christ the righteous one bears the judgment of the unrighteous not merely to spare them from punishment but to bring them into the presence of God. Abraham&#8217;s intercession spares from punishment; Christ&#8217;s intercession brings into life.</p>",
"30": "<p>&#8220;May the Lord not be angry, but let me speak.&#8221; Abraham approaches with holy boldness mixed with holy fear. Christ opens the way for both simultaneously: &#8220;for we do not have a high priest who is unable to empathize with our weaknesses, but we have one who has been tempted in every way, just as we are &#8212; yet he did not sin. Let us then approach God&#8217;s throne of grace with confidence, so that we may receive mercy and find grace to help us in our time of need&#8221; (Heb 4:15&#8211;16). The bold-and-reverent approach that Abraham models is made structurally possible through Christ&#8217;s high priestly work.</p>",
"31": "<p>Twenty righteous would spare the city. Abraham has gone from fifty to twenty &#8212; a 60% reduction &#8212; pressing toward the minimum. The logic reaches its NT terminus in the one Mediator: &#8220;Christ Jesus&#8230; who gave himself as a ransom for all&#8221; (1 Tim 2:5&#8211;6). The decreasing number in Abraham&#8217;s intercession is a biblical-dramatic way of asking: how few will it take? The NT answer: one &#8212; but that one must be the Son of God, because no ordinary righteous person could bear the weight that the intercession of v31 implies.</p>",
"32": "<p>&#8220;What if only ten can be found there?&#8221; Ten is the minimum for a Jewish prayer quorum (minyan) &#8212; the smallest viable community. Abraham stops at ten; he does not descend to one. But Christ&#8217;s intercession goes to one: himself. &#8220;He always lives to intercede for them&#8221; (Heb 7:25) &#8212; not as one of ten, but as the sole mediator. The intercession of Abraham reaches its limit at ten and Sodom is still destroyed; the intercession of Christ, though it saves all who come, leaves no limit of righteousness uncrossed by the one righteous one at the Father&#8217;s right hand.</p>",
"33": "<p>The LORD finished speaking and left; Abraham returned home. The intercession ends at the divine departure &#8212; finite, occasional, limited. Christ&#8217;s intercession is the contrast: &#8220;he always lives to intercede for them&#8221; (Heb 7:25). The intercession that Abraham performed at Mamre is permanent in Christ at the Father&#8217;s right hand. The departure of God after each OT theophany &#8212; after Mamre, after Sinai, after the temple&#8217;s glory &#8212; is the departure that the ascension reverses: Christ goes up to the Father and sends the Spirit to be with his people always (John 14:16&#8211;17; 16:7).</p>"
},
"19": {
"1": "<p>Lot sits at Sodom&#8217;s gate &#8212; the seat of civic authority (Ruth 4:1&#8211;2; Prov 31:23). Lot&#8217;s position in Sodom marks his deep entanglement with a city he should have avoided. Yet 2 Pet 2:7&#8211;8 calls him &#8220;a righteous man, who was distressed by the depraved conduct of the lawless&#8221; &#8212; his righteousness was genuine but his situation compromised. Lot is the type of the believer whose soul is saved &#8220;only as one escaping through the flames&#8221; (1 Cor 3:15) &#8212; not the model of faith (that is Abraham in ch18) but the evidence of divine mercy that rescues even compromised faithfulness.</p>",
"2": "<p>Lot urges the angels to stay at his house; they initially refuse. The angels who bring salvation linger outside unless invited in &#8212; a pattern that Christ explicitly describes: &#8220;Here I am! I stand at the door and knock. If anyone hears my voice and opens the door, I will come in and eat with that person, and they with me&#8221; (Rev 3:20). Salvation comes to those who insist on it &#8212; like Lot pressing the angels, like blind Bartimaeus crying out despite being hushed (Mark 10:48), like the Syrophoenician woman who refuses to be turned away (Matt 15:27). The persistent welcome is the faith that receives the Savior.</p>",
"3": "<p>Lot bakes unleavened bread (<em>maṣṣôt</em>) for his guests &#8212; the same bread of haste that Passover will require (Exod 12:15&#8211;20). The unleavened bread at the divine table is the bread of urgent departure from a condemned place. Paul in 1 Cor 5:7&#8211;8 uses unleavened bread as a metaphor for the purity that Christ&#8217;s Passover sacrifice enables: &#8220;Christ, our Passover lamb, has been sacrificed. Therefore let us keep the Festival, not with the old bread leavened with malice and wickedness, but with the unleavened bread of sincerity and truth.&#8221; The unleavened bread Lot prepares in Sodom is a quiet pointer toward the Passover that defines the new covenant.</p>",
"4": "<p>All the men of Sodom &#8212; young and old, every part of the city &#8212; surround Lot&#8217;s house. The comprehensive wickedness &#8212; not a minority but the entire population &#8212; makes the judgment inescapable. Jude 7 &#8212; &#8220;Sodom and Gomorrah and the surrounding towns gave themselves up to sexual immorality and perversion. They serve as an example of those who suffer the punishment of eternal fire.&#8221; The totality of Sodom&#8217;s corruption is the reason judgment is complete; there are not even ten righteous (18:32). The judgment that falls completely on Sodom falls completely on Christ at the cross so that it need not fall completely on those who are in him.</p>",
"5": "<p>The Sodomites demand that the men be brought out for sexual violence. The comprehensive sexual violence of Sodom is the moral nadir of the pre-Abrahamic Gentile world &#8212; the same depravity that Paul diagnoses in Rom 1:24&#8211;27 as the result of the Gentile world exchanging the Creator for created things. Christ comes into exactly this corrupted world &#8212; &#8220;he came to what was his own, but his own did not receive him&#8221; (John 1:11). The violence of Sodom represents the extreme end of the moral condition that makes the gospel both necessary and urgent.</p>",
"6": "<p>Lot went outside and shut the door behind him, placing himself between the angels and the mob. Lot&#8217;s protective posture &#8212; placing himself between the vulnerable and the violent &#8212; is the posture of the shepherd who guards the sheep: &#8220;the good shepherd lays down his life for the sheep&#8221; (John 10:11). The action is imperfect (Lot&#8217;s subsequent offer in v8 is morally disastrous) but the impulse of protective self-interposition is the impulse that Christ perfectly fulfills. The flawed shepherd of v6 is the shadow of the Good Shepherd who stands definitively between his people and the destroyers.</p>",
"7": "<p>&#8220;Don&#8217;t do this wicked thing.&#8221; Lot&#8217;s moral objection &#8212; feeble and inadequate, about to be undercut by his own compromise (v8) &#8212; is still a moral witness in the heart of Sodom. Christ is the ultimate moral witness who does not compromise his objection to evil: &#8220;the prince of this world is coming. He has no hold over me&#8221; (John 14:30). Where Lot&#8217;s moral witness fails under pressure, Christ&#8217;s holds absolutely &#8212; he is the one who &#8220;has been tempted in every way, just as we are &#8212; yet he did not sin&#8221; (Heb 4:15).</p>",
"8": "<p>Lot&#8217;s offer of his daughters &#8212; the most troubling moment of an already troubled chapter. Lot prioritizes his duty to guests over his duty to his daughters; the moral framework is ancient Near Eastern hospitality culture at its most extreme, and it is not commended. The narrative presents it without comment; the NT does not endorse it. The contrast with Christ is stark: Christ gives himself, not others, to be violated; the Shepherd lays down his own life, not the sheep&#8217;s (John 10:11). The horror of v8 makes the gospel of Christ&#8217;s substitutionary self-giving more luminous by contrast.</p>",
"9": "<p>The mob presses against Lot, threatening him too. The one who placed himself between the angels and the violent now faces the same violence himself. The logic of intercession leads to this: Abraham&#8217;s intercession was from outside; Christ&#8217;s intercession is from inside, entering the place of danger himself. &#8220;God made him who had no sin to be sin for us&#8221; (2 Cor 5:21) &#8212; Christ enters the place of judgment, not as an observer but as the one upon whom the judgment falls. Lot is about to be rescued by the very ones he was trying to protect; Christ is not rescued from the cross, because the cross is his purpose (John 12:27).</p>",
"10": "<p>The angels reach out and pull Lot inside to safety, shutting the door. The divine rescue &#8212; God intervening at the moment of threat to draw his people to safety. John 10:28&#8211;29 &#8212; &#8220;no one will snatch them out of my hand&#8230; no one can snatch them out of my Father&#8217;s hand.&#8221; The hand that pulled Lot inside and shut the door against the violent mob is the hand of Christ that holds his people against all who would seize them. The divine rescue of v10 is instantaneous, physical, and complete &#8212; the same qualities Paul attributes to the final rescue of believers: &#8220;the dead will be raised imperishable, and we will be changed&#8221; (1 Cor 15:52).</p>",
"11": "<p>The men of Sodom are struck with blindness, unable to find the door. The blindness that falls on those who pursue what is forbidden is both judgment and mercy &#8212; it prevents them from carrying out their intention. Christ diagnoses the same blindness in the religious leaders: &#8220;for judgment I have come into this world, so that the blind will see and those who see will become blind&#8221; (John 9:39). The blindness at Lot&#8217;s door is the judicial blindness that protects the holy from the profane; the blindness of those who reject Christ is the judicial blindness that Paul describes in 2 Cor 4:4 &#8212; &#8220;the god of this age has blinded the minds of unbelievers.&#8221;</p>",
"12": "<p>The angels ask who else belongs to Lot: &#8220;Get them out of here.&#8221; The divine urgency to gather all who belong to the righteous man before judgment falls. Christ speaks the same urgency: &#8220;I have other sheep that are not of this sheep pen. I must bring them also&#8221; (John 10:16); the disciples sent out in Matt 10 are to find those who are worthy in each city before moving on. The angels&#8217; concern for Lot&#8217;s complete household is the model of Christ&#8217;s concern for every person who belongs to him &#8212; &#8220;of all those he has given me I shall lose none&#8221; (John 6:39).</p>",
"13": "<p>&#8220;We are going to destroy this place. The outcry to the LORD against its people is so great that he has sent us to destroy it.&#8221; The judgment that the outcry (cf. 18:20) has brought &#8212; the cry of the oppressed reaching God and precipitating divine action. The final judgment that Christ executes is also precipitated by the cry of the martyrs: &#8220;How long, Sovereign Lord, holy and true, until you judge the inhabitants of the earth and avenge our blood?&#8221; (Rev 6:10). The judgment on Sodom &#8212; in response to outcry, executed through divine agents &#8212; is the type of the final judgment that Christ will execute in response to the accumulated outcry of all history&#8217;s victims.</p>",
"14": "<p>Lot&#8217;s sons-in-law thought he was joking. The mockers who refuse the warning of coming judgment &#8212; the pattern that 2 Pet 3:3&#8211;4 applies to the rejection of Christ&#8217;s return: &#8220;in the last days scoffers will come, scoffing and saying, &#8216;Where is this &#8220;coming&#8221; he promised?&#8217;&#8221; Jesus cites the days of Noah (not Sodom) and the days of Lot in the same breath (Luke 17:26&#8211;29) as warnings about the same danger: the fatal casualness of those who treat the warning of divine judgment as a joke. The sons-in-law who laugh at Lot&#8217;s warning perish in Sodom; those who laugh at Christ&#8217;s warning of judgment will face a greater Sodom.</p>",
"15": "<p>The angels urge Lot at dawn: &#8220;Hurry! Take your wife and your two daughters&#8230; or you will be swept away.&#8221; The urgency of rescue &#8212; the window of salvation is closing. The same urgency marks the gospel: &#8220;now is the time of God&#8217;s favor, now is the day of salvation&#8221; (2 Cor 6:2). Christ&#8217;s parable of the ten virgins (Matt 25:1&#8211;13) carries the same urgency &#8212; the door is shut at the appointed time, and those who delay are excluded. The angels&#8217; dawn-urgency is the urgency of the gospel that does not wait for a more convenient time.</p>",
"16": "<p>Lot hesitated; the angels grasped his hand and led him out &#8212; &#8220;for the LORD was merciful to him.&#8221; The theological heart of the chapter: Lot is not rescued because of his deserving (he hesitated!) but because God is merciful. Eph 2:4&#8211;5 &#8212; &#8220;because of his great love for us, God, who is rich in mercy, made us alive with Christ even when we were dead in transgressions &#8212; it is by grace you have been saved.&#8221; The angels grasp Lot&#8217;s hesitating hand &#8212; divine grace that does not wait for the sinner to be ready but acts in mercy toward the undeserving. This is the mercy fully embodied in Christ.</p>",
"17": "<p>&#8220;Flee for your lives! Don&#8217;t look back.&#8221; Jesus cites this command in Luke 17:31&#8211;33 as a warning about the urgency of response when the Son of Man comes: &#8220;On that day no one who is on the housetop, with possessions inside, should go down to get them&#8230; Remember Lot&#8217;s wife!&#8221; The command to not look back &#8212; not to be drawn back to what is being destroyed &#8212; is Christ&#8217;s warning about attachment to the present age that is passing away (1 John 2:15&#8211;17; Phil 3:13&#8211;14 &#8212; &#8220;forgetting what is behind and straining toward what is ahead&#8221;). Salvation requires forward momentum, not nostalgia for Sodom.</p>",
"18": "<p>&#8220;No, my lords, please!&#8221; Lot bargains with the angels rather than simply obeying. The fear that generates the alternative request &#8212; flee to a small city instead of the mountains &#8212; is the fear that perfect love casts out (1 John 4:18). Christ does not bargain with the Father&#8217;s plan in Gethsemane &#8212; he asks if the cup can pass but ultimately says &#8220;not as I will, but as you will&#8221; (Matt 26:39). Lot&#8217;s bargaining with the angels is the contrast to Christ&#8217;s submission &#8212; yet God in mercy grants even Lot&#8217;s diminished request, just as grace meets believers where they are in faith&#8217;s weakness (Rom 15:1).</p>",
"19": "<p>&#8220;Your servant has found favor in your eyes.&#8221; Lot knows his rescue is based on divine favor &#8212; the same <em>ḥēn</em> (grace) that Noah found (6:8). The rescue from Sodom is not based on Lot&#8217;s moral perfection (v8 eliminates that possibility) but on divine mercy. This is the pattern of all salvation in both testaments: &#8220;it is by grace you have been saved, through faith &#8212; and this is not from yourselves, it is the gift of God &#8212; not by works, so that no one can boast&#8221; (Eph 2:8&#8211;9). Lot&#8217;s acknowledgment of divine favor as the basis of his rescue is the acknowledgment that every saved sinner must make.</p>",
"20": "<p>&#8220;Let me flee to it &#8212; it is very small.&#8221; Lot&#8217;s diminished faith seeks a diminished refuge. The contrast with the &#8220;city with foundations&#8221; that Abraham seeks (Heb 11:10) is stark. Lot settles for Zoar (&#8220;small&#8221;) rather than the security God offered in the mountains. Yet even this small city is granted &#8212; God&#8217;s grace meets weak faith with generous accommodation. Christ meets people where they are: &#8220;a bruised reed he will not break, and a smoldering wick he will not snuff out&#8221; (Matt 12:20, citing Isa 42:3). The God of grace does not discard the one whose faith reaches only to Zoar.</p>",
"21": "<p>&#8220;Very well, I will grant this request too; I will not overthrow the town you speak of.&#8221; God accedes to Lot&#8217;s lesser request &#8212; divine flexibility in response to human weakness. The same accommodating grace marks Christ&#8217;s ministry: he heals the paralytic and forgives sins (Mark 2:5) because he sees what the person most needs. God&#8217;s willingness to spare Zoar for Lot&#8217;s sake shows that the scope of mercy in the Sodom narrative is wider than the destruction &#8212; grace extends beyond the individual to those whom the saved person cares for. This is the intercessory dynamic: Abraham&#8217;s prayer saves Lot; Lot&#8217;s request saves Zoar.</p>",
"22": "<p>&#8220;I cannot do anything until you reach it.&#8221; Divine judgment restrained for the sake of the righteous who must first reach safety. 2 Pet 3:9 &#8212; &#8220;the Lord is not slow in keeping his promise&#8230; he is patient with you, not wanting anyone to perish, but everyone to come to repentance.&#8221; The delay of Christ&#8217;s return is the delay of judgment for the sake of those not yet reached by the gospel. The same mercy that held back Sodom&#8217;s fire until Lot reached Zoar holds back the final judgment until the full number of the Gentiles has come in (Rom 11:25). Judgment waits on the completion of rescue.</p>",
"23": "<p>The sun rose over the land as Lot reached Zoar. The dawn &#8212; the very moment of light&#8217;s arrival &#8212; is the moment Lot&#8217;s rescue is complete. The day imagery runs through Scripture toward Christ: &#8220;the sun of righteousness will rise with healing in its rays&#8221; (Mal 4:2); &#8220;the rising sun came to us from heaven to shine on those living in darkness and in the shadow of death&#8221; (Luke 1:78&#8211;79). The dawn of Lot&#8217;s rescue is the type of the dawn of salvation that Christ brings &#8212; the true dawn after the long night of sin&#8217;s darkness.</p>",
"24": "<p>&#8220;The LORD rained down burning sulfur on Sodom and Gomorrah &#8212; from the LORD out of the heavens.&#8221; The double mention of &#8220;the LORD&#8221; has been read as a Trinitarian formula &#8212; one LORD on earth, one out of the heavens (a reading by Justin Martyr and Origen). More securely, the judgment on Sodom is the most prominent OT type of the final judgment. 2 Pet 2:6 &#8212; God &#8220;condemned the cities of Sodom and Gomorrah by burning them to ashes, and made them an example of what is going to happen to the ungodly.&#8221; Luke 17:29 &#8212; &#8220;the day Lot left Sodom, fire and sulfur rained down from heaven and destroyed them all &#8212; it will be just like this on the day the Son of Man is revealed.&#8221; Christ is both the executor of this final judgment (John 5:22) and the rescue from it.</p>",
"25": "<p>The cities, the entire plain, and all the vegetation destroyed. The totality of the judgment &#8212; cities, people, land, plants &#8212; is the preview of the total judgment at the end of the age: &#8220;the earth and everything done in it will be laid bare&#8221; (2 Pet 3:10). Yet what follows in Scripture is not permanent desolation but new creation: &#8220;we are looking forward to a new heaven and a new earth, where righteousness dwells&#8221; (2 Pet 3:13). The total destruction of Sodom is not the final word &#8212; the total recreation that Christ inaugurates is. Judgment and new creation are the two poles, with Christ standing at both: executing judgment (John 5:22) and making all things new (Rev 21:5).</p>",
"26": "<p>Lot&#8217;s wife looked back and became a pillar of salt. Jesus cites this directly: &#8220;Remember Lot&#8217;s wife!&#8221; (Luke 17:32) &#8212; in the context of the coming of the Son of Man. The warning is about the fatal cost of attachment to what is being left behind: &#8220;whoever tries to keep their life will lose it, and whoever loses their life will preserve it&#8221; (Luke 17:33). The pillar of salt that marks Lot&#8217;s wife&#8217;s end is a monument to the danger of incomplete surrender &#8212; of escaping Sodom in body while the heart remains there. Christ&#8217;s summons to discipleship has the same shape: &#8220;no one who puts a hand to the plow and looks back is fit for service in the kingdom of God&#8221; (Luke 9:62).</p>",
"27": "<p>Abraham rises early and returns to where he had stood before the LORD, looking out over the smoking plain. The faithful intercessor surveys the outcome of the divine action &#8212; the prayer was not granted as asked (Sodom is destroyed; fewer than ten righteous were found), yet Lot was saved (v29). The intercession that could not save Sodom did save Lot. This is the pattern of Christ&#8217;s intercession: he does not always grant what is asked in the form it is asked, but those who belong to him are kept (John 17:12 &#8212; &#8220;not one of them is lost except the one doomed to destruction&#8221;). The intercessor stands the morning after the judgment and surveys what the prayer accomplished.</p>",
"28": "<p>Dense smoke rising from Sodom &#8212; &#8220;like smoke from a furnace.&#8221; The imagery of Sodom&#8217;s smoke recurs in Revelation as the smoke of divine judgment: &#8220;the smoke of their torment will rise for ever and ever&#8221; (Rev 14:11); &#8220;the smoke from her goes up for ever and ever&#8221; (Rev 19:3 &#8212; of Babylon, the great Sodom). Abraham witnesses from a distance what the judgment produces. The distance from which Abraham observes &#8212; the intercessor watching judgment fall &#8212; is the distance Christ bridges: he does not observe the judgment from a distance but enters it (Matt 27:46 &#8212; &#8220;my God, my God, why have you forsaken me?&#8221;), absorbing it rather than merely watching it fall.</p>",
"29": "<p>&#8220;God remembered Abraham and brought Lot out of the catastrophe.&#8221; The intercessory connection is explicit: Lot is rescued because God remembered Abraham. This is the pattern of all intercession: what the intercessor prays for is accomplished through the intercessor&#8217;s standing with God, not through the merits of the one rescued. Christ&#8217;s intercession operates on the same principle: those who are saved are saved because God remembers Christ &#8212; his finished work, his continued prayer. &#8220;He always lives to intercede for them&#8221; (Heb 7:25) is the NT equivalent of &#8220;God remembered Abraham.&#8221;</p>",
"30": "<p>Lot leaves Zoar &#8212; the lesser refuge he chose &#8212; and ends up in the mountains that the angels originally directed him to. The fear that made Lot request Zoar instead of the mountains was unfounded; the original instruction was better. The same pattern recurs in the believer&#8217;s journey: the ways we negotiate for easier paths often lead us back to the harder way that was God&#8217;s original instruction. Christ&#8217;s narrow way (Matt 7:14 &#8212; &#8220;narrow the road that leads to life&#8221;) is precisely the harder direction that the disciples are tempted to avoid &#8212; but it is the direction of true security.</p>",
"31": "<p>The older daughter speaks &#8212; believing there are no men left in the world. The catastrophic distortion of the daughters&#8217; world-view (they believe all civilization has been destroyed) drives their desperate plan. The plan is not commended; it is the action of people reasoning from fear and limited information. The contrast with the God who knows all things and provides legitimately is the implicit theological judgment. Christ comes to give what fear-driven human plans cannot: &#8220;I have come that they may have life, and have it to the full&#8221; (John 10:10) &#8212; the full life that the daughters tried to manufacture through a desperate and sinful shortcut.</p>",
"32": "<p>The daughters plan to preserve their family line through their father. The urgency to preserve the line &#8212; however desperate and wrong the means &#8212; mirrors the urgency that runs through all of Genesis: the seed must be preserved. Even in this broken context, the instinct to perpetuate the covenant line is present, however perversely expressed. God&#8217;s providence works through and despite human sin to preserve the line that leads to Christ &#8212; as it will through Tamar&#8217;s deception (ch38) and Rahab&#8217;s profession (Josh 2). The brokenness of the human vessels does not stop the divine purpose.</p>",
"33": "<p>The daughters act on their plan. The narrative records without comment or excuse what happened. The theological point is not that the daughters&#8217; action was acceptable but that God&#8217;s providence is not thwarted by human sin. This is the pattern of the entire biblical genealogy: &#8220;God causes all things to work together for good for those who love God&#8221; (Rom 8:28) &#8212; not because all things are good but because God&#8217;s redemptive purpose is greater than human failure. The incest of this night will produce Moab &#8212; from whom Ruth will come &#8212; and Ruth is in the genealogy of Christ (Matt 1:5). Providence moves through the darkest human moments.</p>",
"34": "<p>The older daughter instructs the younger to repeat what she did. The plan continues &#8212; deliberate, not accidental. The moral darkness of the passage does not resolve into anything edifying within the chapter itself. The resolution comes later: from Moab comes Ruth; from Ruth comes David; from David comes Christ. The longest arcs of redemption move through the most morally complex situations. This is the grace that Paul describes: &#8220;where sin increased, grace increased all the more&#8221; (Rom 5:20). The grace that brings Christ from this origin is greater than the sin that produced it.</p>",
"35": "<p>The younger daughter sleeps with Lot. The second night completes the plan. The repetition emphasizes the deliberateness of the act &#8212; no ambiguity about what happened. Scripture does not sanitize the genealogy of the Messiah; the Bible includes this account precisely because the genealogy of Christ moves through broken humanity. Matt 1&#8217;s genealogy includes Tamar (incest), Rahab (prostitute), Ruth (Gentile), Bathsheba (adultery) &#8212; precisely the kind of moral complexity that culminates with this chapter. Christ comes from broken humanity in order to redeem it from within.</p>",
"36": "<p>Both daughters become pregnant by their father. The two pregnancies that will produce Moab and Ammon &#8212; Israel&#8217;s persistent neighbors and often antagonists. Yet even this compromised origin is within God&#8217;s sovereign purpose. Ruth 4:21&#8211;22 is the genealogical resolution: Boaz (of Judah) marries Ruth (of Moab) &#8212; the line of promise and the line of Moab converging in one marriage that leads to David and to Christ. The sinful origin of Moab does not prevent God from grafting the Moabite branch into the tree of Jesse (Rom 11:17).</p>",
"37": "<p>Moab &#8212; father of the Moabites. The Moabites who descend from this act include Ruth, who comes to Israel with Naomi and declares &#8220;your people will be my people and your God my God&#8221; (Ruth 1:16) &#8212; perhaps the most beautiful conversion declaration in the OT. Ruth&#8217;s loyalty leads to marriage with Boaz, and their son Obed is the grandfather of David (Ruth 4:21&#8211;22). Matthew includes Ruth in Christ&#8217;s genealogy (Matt 1:5): the Moabite great-grandmother of David is the Moabite ancestor of Christ. God redeems even the origin of Moab &#8212; born of incest after the destruction of Sodom &#8212; by bringing his Son through Ruth&#8217;s line. This is the grace that exceeds all human failure.</p>",
"38": "<p>Ben-Ammi &#8212; father of the Ammonites. The Ammonites are often Israel&#8217;s adversaries, yet even they are within the scope of the universal redemption Christ offers. More immediately, the narrative of Lot&#8217;s daughters ends not with moral resolution but with the reality of broken human action producing new peoples within God&#8217;s providential world. The God who turns water into wine (John 2:9), who brings life from Sarah&#8217;s dead womb (17:17&#8211;19), who raises Christ from the dead &#8212; this is the God who brings Ruth from Moab and from Moab brings David and from David brings Christ. The brokenness of v38 is not the end of the story; it is the beginning of the line that ends with the one who makes all things new (Rev 21:5).</p>"
}
}

def main():
    existing = load_comm('mkt-christ', 'genesis')
    merge_comm(existing, NEW_DATA)
    save_comm('mkt-christ', 'genesis', existing)
    print(f"  ch17 verses: {len(existing.get('17', {}))}")
    print(f"  ch18 verses: {len(existing.get('18', {}))}")
    print(f"  ch19 verses: {len(existing.get('19', {}))}")
    print("Genesis 17–19 mkt-christ written.")

if __name__ == '__main__':
    main()
